@Immutable
data class UserUi(
    val id: String,
    val name: String,
    val avatarUrl: String?
)

@Composable
fun UserRow(model: UserUi, onClick: (String) -> Unit) {
    Text(model.name, Modifier.clickable { onClick(model.id) })
}

@Composable
fun FeedScreen(state: FeedUiState) {
    FeedList(state.items)
}

@Composable
private fun FeedList(items: ImmutableList<PostUi>) {
    LazyColumn {
        items(items, key = { it.id }) { PostRow(it) }
    }
}

data class JobCardUi(val id: String, val title: String, val saved: Boolean)

fun List<JobCardUi>.toggle(id: String) = map {
    if (it.id == id) it.copy(saved = !it.saved) else it
}

@Composable
fun JobList(items: List<JobCardUi>, onToggle: (String) -> Unit) {
    LazyColumn {
        items(items, key = { it.id }) { item ->
            JobCard(item) { onToggle(item.id) }
        }
    }
}

@Composable
fun CollapsingHeader(listState: LazyListState) {
    val collapsed by remember {
        derivedStateOf { listState.firstVisibleItemIndex > 0 }
    }
    Header(collapsed)
}

@Immutable
data class FeedUiState(val posts: ImmutableList<PostUi>)

fun FeedUiState.updateReaction(id: String, count: Int) =
    copy(posts = posts.map {
        if (it.id == id) it.copy(reactionCount = count) else it
    }.toImmutableList())
